package com.example.mfabackupcodes.config;

import com.example.mfabackupcodes.service.JpaUserDetailsService;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.AuthenticationSuccessHandler;
import org.springframework.security.web.authentication.SimpleUrlAuthenticationSuccessHandler;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    private final JpaUserDetailsService jpaUserDetailsService;

    public SecurityConfig(JpaUserDetailsService jpaUserDetailsService) {
        this.jpaUserDetailsService = jpaUserDetailsService;
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .authorizeHttpRequests(authorize -> authorize
                .requestMatchers("/", "/register", "/css/**", "/js/**", "/webjars/**").permitAll()
                .requestMatchers("/login", "/login-mfa", "/login-backup-code").permitAll() // Allow these login pages
                .anyRequest().authenticated()
            )
            .formLogin(form -> form
                .loginPage("/login")
                .loginProcessingUrl("/login")
                .successHandler(authenticationSuccessHandler())
                .failureUrl("/login?error")
                .permitAll()
            )
            .logout(logout -> logout
                .logoutUrl("/logout")
                .logoutSuccessUrl("/login?logout")
                .permitAll()
            );
        return http.build();
    }

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder();
    }

    @Bean
    public AuthenticationSuccessHandler authenticationSuccessHandler() {
        return (request, response, authentication) -> {
            // Check if the user is an instance of our custom UserDetails
            if (authentication.getPrincipal() instanceof JpaUserDetailsService.CustomUserDetails customUserDetails) {
                if (customUserDetails.isMfaEnabled() && !customUserDetails.isMfaVerified()) {
                    response.sendRedirect("/login-mfa"); // Redirect to MFA verification page
                    return;
                }
            }
            // Default behavior if no MFA or MFA already verified, or not customUserDetails
            new SimpleUrlAuthenticationSuccessHandler("/dashboard").onAuthenticationSuccess(request, response, authentication);
        };
    }
}

package com.example.mfabackupcodes.controller;

import com.example.mfabackupcodes.model.User;
import com.example.mfabackupcodes.service.MfaService;
import com.example.mfabackupcodes.service.UserService;
import jakarta.servlet.http.HttpServletRequest;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.ModelAttribute;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.servlet.mvc.support.RedirectAttributes;

import java.util.Optional;

@Controller
public class AuthController {

    private final UserService userService;
    private final MfaService mfaService;

    public AuthController(UserService userService, MfaService mfaService) {
        this.userService = userService;
        this.mfaService = mfaService;
    }

    @GetMapping("/login")
    public String login(@RequestParam Optional<String> error, Model model) {
        error.ifPresent(s -> model.addAttribute("error", "Invalid username or password."));
        return "login";
    }

    @GetMapping("/register")
    public String register(Model model) {
        model.addAttribute("user", new User());
        return "register";
    }

    @PostMapping("/register")
    public String registerUser(@ModelAttribute("user") User user, RedirectAttributes redirectAttributes) {
        if (userService.findByUsername(user.getUsername()).isPresent()) {
            redirectAttributes.addFlashAttribute("error", "Username already exists.");
            return "redirect:/register";
        }
        userService.registerUser(user);
        redirectAttributes.addFlashAttribute("message", "Registration successful. Please login.");
        return "redirect:/login";
    }

    @GetMapping("/login-mfa")
    public String showMfaLogin(Model model) {
        if (!SecurityContextHolder.getContext().getAuthentication().isAuthenticated() ||
                SecurityContextHolder.getContext().getAuthentication().getPrincipal().equals("anonymousUser")) {
            return "redirect:/login"; // Not authenticated via username/password yet
        }
        model.addAttribute("username", SecurityContextHolder.getContext().getAuthentication().getName());
        return "login-mfa";
    }

    @PostMapping("/login-mfa")
    public String verifyMfaLogin(@RequestParam String code, RedirectAttributes redirectAttributes) {
        String username = SecurityContextHolder.getContext().getAuthentication().getName();
        User user = userService.findByUsername(username).orElseThrow(() -> new RuntimeException("User not found after primary auth"));

        if (mfaService.validateTotp(user.getMfaSecret(), code)) {
            // Successfully verified MFA, update the authentication object
            // This is a simplified way to "promote" the authentication
            UsernamePasswordAuthenticationToken auth =
                    new UsernamePasswordAuthenticationToken(user.getUsername(), user.getPassword(), user.getAuthorities());
            SecurityContextHolder.getContext().setAuthentication(auth);
            redirectAttributes.addFlashAttribute("message", "MFA verified. Welcome!");
            return "redirect:/dashboard";
        } else {
            redirectAttributes.addFlashAttribute("error", "Invalid MFA code.");
            return "redirect:/login-mfa";
        }
    }

    @GetMapping("/login-backup-code")
    public String showBackupCodeLogin(Model model) {
        if (!SecurityContextHolder.getContext().getAuthentication().isAuthenticated() ||
                SecurityContextHolder.getContext().getAuthentication().getPrincipal().equals("anonymousUser")) {
            return "redirect:/login"; // Not authenticated via username/password yet
        }
        model.addAttribute("username", SecurityContextHolder.getContext().getAuthentication().getName());
        return "login-backup-code";
    }

    @PostMapping("/login-backup-code")
    public String verifyBackupCodeLogin(@RequestParam String backupCode, RedirectAttributes redirectAttributes) {
        String username = SecurityContextHolder.getContext().getAuthentication().getName();
        User user = userService.findByUsername(username).orElseThrow(() -> new RuntimeException("User not found after primary auth"));

        if (userService.useBackupCode(user, backupCode)) {
            // Successfully used backup code, update the authentication object
            UsernamePasswordAuthenticationToken auth =
                    new UsernamePasswordAuthenticationToken(user.getUsername(), user.getPassword(), user.getAuthorities());
            SecurityContextHolder.getContext().setAuthentication(auth);
            redirectAttributes.addFlashAttribute("message", "Backup code verified. Welcome!");
            return "redirect:/dashboard";
        } else {
            redirectAttributes.addFlashAttribute("error", "Invalid or used backup code.");
            return "redirect:/login-backup-code";
        }
    }
}

package com.example.mfabackupcodes.controller;

import com.example.mfabackupcodes.model.BackupCode;
import com.example.mfabackupcodes.model.User;
import com.example.mfabackupcodes.service.BackupCodeService;
import com.example.mfabackupcodes.service.MfaService;
import com.example.mfabackupcodes.service.UserService;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.servlet.mvc.support.RedirectAttributes;

import java.util.List;
import java.util.Optional;

@Controller
@RequestMapping("/mfa")
public class MfaController {

    private final UserService userService;
    private final MfaService mfaService;
    private final BackupCodeService backupCodeService;

    public MfaController(UserService userService, MfaService mfaService, BackupCodeService backupCodeService) {
        this.userService = userService;
        this.mfaService = mfaService;
        this.backupCodeService = backupCodeService;
    }

    @GetMapping("/setup")
    public String setupMfa(Model model, @AuthenticationPrincipal UserDetails currentUser) {
        User user = userService.findByUsername(currentUser.getUsername())
                .orElseThrow(() -> new RuntimeException("User not found"));

        if (user.isMfaEnabled()) {
            model.addAttribute("mfaEnabled", true);
            return "mfa-setup"; // Show already enabled page
        }

        String newSecret = mfaService.generateSecret();
        String qrCodeImageUrl = mfaService.getQrCodeImageUrl(newSecret, user.getUsername());

        model.addAttribute("secret", newSecret);
        model.addAttribute("qrCodeImageUrl", qrCodeImageUrl);
        model.addAttribute("user", user);
        return "mfa-setup";
    }

    @PostMapping("/verify-setup")
    public String verifyMfaSetup(@AuthenticationPrincipal UserDetails currentUser,
                                 @RequestParam("secret") String secret,
                                 @RequestParam("code") String code,
                                 RedirectAttributes redirectAttributes) {
        User user = userService.findByUsername(currentUser.getUsername())
                .orElseThrow(() -> new RuntimeException("User not found"));

        if (mfaService.validateTotp(secret, code)) {
            user.setMfaEnabled(true);
            user.setMfaSecret(secret);
            userService.save(user);

            List<String> backupCodes = backupCodeService.generateAndStoreBackupCodes(user);
            redirectAttributes.addFlashAttribute("message", "MFA enabled successfully! Please save your backup codes.");
            redirectAttributes.addFlashAttribute("backupCodes", backupCodes);
            return "redirect:/mfa/backup-codes";
        } else {
            redirectAttributes.addFlashAttribute("error", "Invalid verification code.");
            return "redirect:/mfa/setup";
        }
    }

    @PostMapping("/disable")
    public String disableMfa(@AuthenticationPrincipal UserDetails currentUser, RedirectAttributes redirectAttributes) {
        User user = userService.findByUsername(currentUser.getUsername())
                .orElseThrow(() -> new RuntimeException("User not found"));

        user.setMfaEnabled(false);
        user.setMfaSecret(null);
        userService.save(user);
        backupCodeService.deleteAllForUser(user); // Delete backup codes if MFA is disabled
        redirectAttributes.addFlashAttribute("message", "MFA disabled successfully.");
        return "redirect:/dashboard";
    }

    @GetMapping("/backup-codes")
    public String viewBackupCodes(Model model, @AuthenticationPrincipal UserDetails currentUser,
                                  @RequestParam("regenerate") Optional<String> regenerate) {
        User user = userService.findByUsername(currentUser.getUsername())
                .orElseThrow(() -> new RuntimeException("User not found"));

        if (!user.isMfaEnabled()) {
            return "redirect:/mfa/setup"; // Can't manage backup codes if MFA isn't enabled
        }

        if (regenerate.isPresent()) {
            backupCodeService.deleteAllForUser(user);
            List<String> newBackupCodes = backupCodeService.generateAndStoreBackupCodes(user);
            model.addAttribute("backupCodes", newBackupCodes);
            model.addAttribute("message", "New backup codes generated successfully. Please save them immediately.");
        } else {
            List<BackupCode> existingCodes = backupCodeService.getBackupCodesForUser(user);
            if (existingCodes.isEmpty()) {
                List<String> newBackupCodes = backupCodeService.generateAndStoreBackupCodes(user);
                model.addAttribute("backupCodes", newBackupCodes);
                model.addAttribute("message", "Backup codes generated. Please save them immediately.");
            } else {
                model.addAttribute("existingCodes", existingCodes);
            }
        }
        return "mfa-backup-codes";
    }
}

